import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertNotNull;
import static org.junit.Assert.assertNull;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.annotation.DirtiesContext;
import org.springframework.transaction.annotation.Transactional;

import main.java.ProTeamRosterApplication;
import main.java.entity.ProMascotEntity;
import main.java.service.ProMascotService;

@SpringBootTest(classes = ProTeamRosterApplication.class)
@DirtiesContext(classMode = DirtiesContext.ClassMode.AFTER_EACH_TEST_METHOD)
@Transactional
public class ProMascotServiceTest {

	@BeforeEach
	public void setUp() {
		// Clear existing data
		try {
			ProMascotService.getProMascot(1L);
			ProMascotService.deleteProMascot(1L);
		} catch (Exception e) {
			// Mascot doesn't exist, continue
		}
		try {
			ProMascotService.getProMascot(2L);
			ProMascotService.deleteProMascot(2L);
		} catch (Exception e) {
			// Mascot doesn't exist, continue
		}
		try {
			ProMascotService.getProMascot(3L);
			ProMascotService.deleteProMascot(3L);
		} catch (Exception e) {
			// Mascot doesn't exist, continue
		}

		// Create test data
		ProMascotEntity mascot1 = new ProMascotEntity();
		mascot1.mascotId = 1L;
		mascot1.name = "Giant Bee";
		mascot1.description = "A large buzzing insect";
		mascot1.costume = "Yellow and black stripes";
		mascot1.teamName = "Hornets";
		ProMascotService.createProMascot(mascot1);

		ProMascotEntity mascot2 = new ProMascotEntity();
		mascot2.mascotId = 2L;
		mascot2.name = "Mountain";
		mascot2.description = "A majestic peak";
		mascot2.costume = "Blue and white peaks";
		mascot2.teamName = "Apps";
		ProMascotService.createProMascot(mascot2);

		ProMascotEntity mascot3 = new ProMascotEntity();
		mascot3.mascotId = 3L;
		mascot3.name = "A Stick";
		mascot3.description = "Just a simple stick";
		mascot3.costume = "Brown wood";
		mascot3.teamName = "Switch";
		ProMascotService.createProMascot(mascot3);
	}

	@Test
	public void get_pro_mascot_test() {
		ProMascotEntity mascot = ProMascotService.getProMascot(1L);
		assertNotNull(mascot);
		assertEquals("Giant Bee", mascot.name);
	}

	@Test
	public void get_mascots_by_team_test() {
		java.util.List<ProMascotEntity> mascots = ProMascotService.getMascotsByTeam("Apps");
		assertEquals(1, mascots.size());
		assertEquals("Mountain", mascots.get(0).name);
	}

	@Test
	public void create_pro_mascot_test() {
		ProMascotEntity mascot4 = new ProMascotEntity();
		mascot4.mascotId = 4L;
		mascot4.name = "Dragon";
		mascot4.description = "A fierce mythical creature";
		mascot4.costume = "Green scales and wings";
		mascot4.teamName = "Dragons";

		assertNull(ProMascotService.getProMascot(4L));
		ProMascotService.createProMascot(mascot4);
		assertNotNull(ProMascotService.getProMascot(4L));
	}

	@Test
	public void update_pro_mascot_test() {
		ProMascotEntity mascot2 = new ProMascotEntity();
		mascot2.mascotId = 2L;
		mascot2.description = "Updated description";

		ProMascotEntity beforeUpdate = ProMascotService.getProMascot(2L);
		assertNotNull(beforeUpdate);
		assertEquals("A majestic peak", beforeUpdate.description);

		ProMascotService.updateProMascot(2L, mascot2);

		ProMascotEntity afterUpdate = ProMascotService.getProMascot(2L);
		assertNotNull(afterUpdate);
		assertEquals("Updated description", afterUpdate.description);
	}

	@Test
	public void delete_pro_mascot_test() {
		// First create a mascot to delete
		ProMascotEntity mascot4 = new ProMascotEntity();
		mascot4.mascotId = 4L;
		mascot4.name = "Test Mascot";
		mascot4.description = "Test description";
		mascot4.costume = "Test costume";
		mascot4.teamName = "Test Team";
		ProMascotService.createProMascot(mascot4);

		ProMascotEntity beforeDelete = ProMascotService.getProMascot(4L);
		assertNotNull(beforeDelete);

		ProMascotService.deleteProMascot(4L);

		assertNull(ProMascotService.getProMascot(4L));
	}
}

import static org.junit.Assert.assertTrue;

import org.junit.Before;
import org.junit.Test;

import main.java.entity.ProPlayerEntity;
import main.java.service.ProPlayerService;

public class ProPlayerServiceTest {

	@Before
	public void setUp() {
		ProPlayerEntity player1 = new ProPlayerEntity();
		player1.playerId = 1;
		player1.name = "Kyle";
		player1.position = "Forward";
		player1.teamName = "Hornets";
		player1.age = 24;
		player1.height = 175.26;
		player1.weight = 176.4;
		player1.college = "UNCC";
		player1.salary = 100000.00;
		ProPlayerEntity player2 = new ProPlayerEntity();
		player2.playerId = 2;
		player2.name = "Max";
		player2.position = "Defender";
		player2.teamName = "Apps";
		player2.age = 24;
		player2.height = 173.26;
		player2.weight = 187.4;
		player2.college = "APP";
		player2.salary = 100540.00;
		ProPlayerEntity player3 = new ProPlayerEntity();
		player3.playerId = 3;
		player3.name = "Kat";
		player3.position = "Midfield";
		player3.teamName = "Switch";
		player3.age = 25;
		player3.height = 173.26;
		player3.weight = 187.4;
		player3.college = "ASHE";
		player3.salary = 120547.00;
	}

	@Test
	public void get_pro_player_test() {
		assertTrue(ProPlayerService.getProPlayer(1).name == "Kyle");
	}

	@Test
	public void create_pro_player_test() {
		ProPlayerEntity player4 = new ProPlayerEntity();
		player4.playerId = 4;
		player4.name = "Rush";
		player4.position = "Goalie";
		player4.teamName = "Lilo";
		player4.age = 85;
		player4.height = 73.26;
		player4.weight = 87.4;
		player4.college = "ASHE";
		player4.salary = 120547.00;
		assertTrue(ProPlayerService.getProPlayer(4) == null);
		ProPlayerService.createProPlayer(player4);
		assertTrue(ProPlayerService.getProPlayer(4) != null);
	}

	@Test
	public void update_pro_player_test() {
		ProPlayerEntity player2 = new ProPlayerEntity();
		player2.playerId = 2;
		player2.salary = 1;
		assertTrue(ProPlayerService.getProPlayer(player2.playerId).salary != 999999);
		ProPlayerService.updateProPlayer(player2.playerId, player2);
		assertTrue(ProPlayerService.getProPlayer(player2.playerId).salary == 1);
	}

	@Test
	public void delete_pro_player_test() {
		ProPlayerEntity player4 = new ProPlayerEntity();
		player4.playerId = 4;
		assertTrue(ProPlayerService.getProPlayer(player4.playerId) != null);
		ProPlayerService.deleteProPlayer(player4.playerId);
		assertTrue(ProPlayerService.getProPlayer(player4.playerId) == null);
	}

}

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertNotNull;
import static org.junit.Assert.assertNull;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.annotation.DirtiesContext;
import org.springframework.transaction.annotation.Transactional;

import main.java.ProTeamRosterApplication;
import main.java.entity.ProPlayerEntity;
import main.java.service.ProPlayerService;

@SpringBootTest(classes = ProTeamRosterApplication.class)
@DirtiesContext(classMode = DirtiesContext.ClassMode.AFTER_EACH_TEST_METHOD)
@Transactional
public class ProPlayerServiceTest {

	@BeforeEach
	public void setUp() {
		// Clear existing data
		try {
			ProPlayerService.getProPlayer(1L);
			ProPlayerService.deleteProPlayer(1L);
		} catch (Exception e) {
			// Player doesn't exist, continue
		}
		try {
			ProPlayerService.getProPlayer(2L);
			ProPlayerService.deleteProPlayer(2L);
		} catch (Exception e) {
			// Player doesn't exist, continue
		}
		try {
			ProPlayerService.getProPlayer(3L);
			ProPlayerService.deleteProPlayer(3L);
		} catch (Exception e) {
			// Player doesn't exist, continue
		}

		// Create test data
		ProPlayerEntity player1 = new ProPlayerEntity();
		player1.playerId = 1L;
		player1.name = "Kyle";
		player1.position = "Forward";
		player1.teamName = "Hornets";
		player1.age = 24;
		player1.height = 175.26;
		player1.weight = 176.4;
		player1.college = "UNCC";
		player1.salary = 100000.00;
		ProPlayerService.createProPlayer(player1);

		ProPlayerEntity player2 = new ProPlayerEntity();
		player2.playerId = 2L;
		player2.name = "Max";
		player2.position = "Defender";
		player2.teamName = "Apps";
		player2.age = 24;
		player2.height = 173.26;
		player2.weight = 187.4;
		player2.college = "APP";
		player2.salary = 100540.00;
		ProPlayerService.createProPlayer(player2);

		ProPlayerEntity player3 = new ProPlayerEntity();
		player3.playerId = 3L;
		player3.name = "Kat";
		player3.position = "Midfield";
		player3.teamName = "Switch";
		player3.age = 25;
		player3.height = 173.26;
		player3.weight = 187.4;
		player3.college = "ASHE";
		player3.salary = 120547.00;
		ProPlayerService.createProPlayer(player3);
	}

	@Test
	public void get_pro_player_test() {
		ProPlayerEntity player = ProPlayerService.getProPlayer(1L);
		assertNotNull(player);
		assertEquals("Kyle", player.name);
	}

	@Test
	public void create_pro_player_test() {
		ProPlayerEntity player4 = new ProPlayerEntity();
		player4.playerId = 4L;
		player4.name = "Rush";
		player4.position = "Goalie";
		player4.teamName = "Lilo";
		player4.age = 85;
		player4.height = 73.26;
		player4.weight = 87.4;
		player4.college = "ASHE";
		player4.salary = 120547.00;

		assertNull(ProPlayerService.getProPlayer(4L));
		ProPlayerService.createProPlayer(player4);
		assertNotNull(ProPlayerService.getProPlayer(4L));
	}

	@Test
	public void update_pro_player_test() {
		ProPlayerEntity player2 = new ProPlayerEntity();
		player2.playerId = 2L;
		player2.salary = 1.0;

		ProPlayerEntity beforeUpdate = ProPlayerService.getProPlayer(2L);
		assertNotNull(beforeUpdate);
		assertEquals(100540.00, beforeUpdate.salary, 0.01);

		ProPlayerService.updateProPlayer(2L, player2);

		ProPlayerEntity afterUpdate = ProPlayerService.getProPlayer(2L);
		assertNotNull(afterUpdate);
		assertEquals(1.0, afterUpdate.salary, 0.01);
	}

	@Test
	public void delete_pro_player_test() {
		// First create a player to delete
		ProPlayerEntity player4 = new ProPlayerEntity();
		player4.playerId = 4L;
		player4.name = "Test Player";
		player4.position = "Forward";
		player4.teamName = "Test Team";
		player4.age = 25;
		player4.height = 180.0;
		player4.weight = 175.0;
		player4.college = "TEST";
		player4.salary = 50000.00;
		ProPlayerService.createProPlayer(player4);

		ProPlayerEntity beforeDelete = ProPlayerService.getProPlayer(4L);
		assertNotNull(beforeDelete);

		ProPlayerService.deleteProPlayer(4L);

		assertNull(ProPlayerService.getProPlayer(4L));
	}
}

import static org.junit.Assert.assertTrue;

import org.junit.Before;
import org.junit.Test;

import main.java.entity.ProTeamEntity;
import main.java.service.ProTeamService;

public class ProTeamServiceTest {

	@Before
	public void setUp() {
		ProTeamEntity team1 = new ProTeamEntity();
		team1.teamId = 1;
		team1.city = "Charlotte";
		team1.name = "Hornets";
		team1.mascot = "Giant Bee";
		ProTeamEntity team2 = new ProTeamEntity();
		team2.teamId = 2;
		team2.city = "Hickory";
		team2.name = "Switch";
		team2.mascot = "A Stick";
		ProTeamEntity team3 = new ProTeamEntity();
		team3.teamId = 3;
		team3.city = "Asheville";
		team3.name = "Apps";
		team3.mascot = "Mountain";
	}

	@Test
	public void get_all_teams_test() {
		assertTrue(ProTeamService.getTeams().size() == 3);
	}

	@Test
	public void get_single_team_test() {
		assertTrue(ProTeamService.getSingleTeamAndRoster(1).name == "Hornets");
	}

	@Test
	public void get_teams_by_field_lookup_test() {
		assertTrue(ProTeamService.getTeamsByFieldLookup(null, "Hickory", null).get(0).name == "Switch");
	}

	@Test
	public void create_team_test() {
		ProTeamEntity team4 = new ProTeamEntity();
		team4.teamId = 14;
		team4.city = "Morganton";
		team4.name = "Shadows";
		team4.mascot = "Dirt Roads";
		ProTeamService.createTeam(team4);
		assertTrue(ProTeamService.getSingleTeamAndRoster(team4.teamId) != null);
	}

	@Test
	public void update_team_test() {
		ProTeamEntity team1 = new ProTeamEntity();
		team1.teamId = 1;
		team1.city = "Space";
		assertTrue(ProTeamService.getSingleTeamAndRoster(team1.teamId).city != "Space");
		ProTeamService.updateTeam(team1.teamId, team1);
		assertTrue(ProTeamService.getSingleTeamAndRoster(team1.teamId).city == "Space");
	}

	@Test
	public void delete_team_test() {
		assertTrue(ProTeamService.getSingleTeamAndRoster(1) != null);
		ProTeamService.deleteTeam(1);
		assertTrue(ProTeamService.getSingleTeamAndRoster(1) == null);
	}
}

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertNotNull;
import static org.junit.Assert.assertNull;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.annotation.DirtiesContext;
import org.springframework.test.context.junit.jupiter.SpringExtension;
import org.springframework.transaction.annotation.Transactional;

import main.java.ProTeamRosterApplication;
import main.java.entity.ProTeamEntity;
import main.java.service.ProTeamService;

@SpringBootTest(classes = ProTeamRosterApplication.class, webEnvironment = SpringBootTest.WebEnvironment.NONE)
@ExtendWith(SpringExtension.class)
@DirtiesContext(classMode = DirtiesContext.ClassMode.AFTER_EACH_TEST_METHOD)
@Transactional
public class ProTeamServiceTest {

	@BeforeEach
	public void setUp() {
		// Clear existing data
		ProTeamService.getTeams().forEach(team -> ProTeamService.deleteTeam(team.teamId));

		// Create test data
		ProTeamEntity team1 = new ProTeamEntity();
		team1.teamId = 1L;
		team1.city = "Charlotte";
		team1.name = "Hornets";
		team1.mascot = "Giant Bee";
		ProTeamService.createTeam(team1);

		ProTeamEntity team2 = new ProTeamEntity();
		team2.teamId = 2L;
		team2.city = "Hickory";
		team2.name = "Switch";
		team2.mascot = "A Stick";
		ProTeamService.createTeam(team2);

		ProTeamEntity team3 = new ProTeamEntity();
		team3.teamId = 3L;
		team3.city = "Asheville";
		team3.name = "Apps";
		team3.mascot = "Mountain";
		ProTeamService.createTeam(team3);
	}

	@Test
	public void get_all_teams_test() {
		assertEquals(3, ProTeamService.getTeams().size());
	}

	@Test
	public void get_single_team_test() {
		ProTeamEntity team = ProTeamService.getSingleTeamAndRoster(1L);
		assertNotNull(team);
		assertEquals("Hornets", team.name);
	}

	@Test
	public void get_teams_by_field_lookup_test() {
		java.util.List<ProTeamEntity> teams = ProTeamService.getTeamsByFieldLookup(null, "Hickory", null);
		assertEquals(1, teams.size());
		assertEquals("Switch", teams.get(0).name);
	}

	@Test
	public void create_team_test() {
		ProTeamEntity team4 = new ProTeamEntity();
		team4.teamId = 14L;
		team4.city = "Morganton";
		team4.name = "Shadows";
		team4.mascot = "Dirt Roads";
		ProTeamService.createTeam(team4);

		ProTeamEntity retrieved = ProTeamService.getSingleTeamAndRoster(14L);
		assertNotNull(retrieved);
		assertEquals("Shadows", retrieved.name);
	}

	@Test
	public void update_team_test() {
		ProTeamEntity team1 = new ProTeamEntity();
		team1.teamId = 1L;
		team1.city = "Space";
		team1.name = "Hornets";
		team1.mascot = "Giant Bee";

		ProTeamEntity beforeUpdate = ProTeamService.getSingleTeamAndRoster(1L);
		assertNotNull(beforeUpdate);
		assertEquals("Charlotte", beforeUpdate.city);

		ProTeamService.updateTeam(1L, team1);

		ProTeamEntity afterUpdate = ProTeamService.getSingleTeamAndRoster(1L);
		assertNotNull(afterUpdate);
		assertEquals("Space", afterUpdate.city);
	}

	@Test
	public void delete_team_test() {
		ProTeamEntity beforeDelete = ProTeamService.getSingleTeamAndRoster(1L);
		assertNotNull(beforeDelete);

		ProTeamService.deleteTeam(1L);

		ProTeamEntity afterDelete = ProTeamService.getSingleTeamAndRoster(1L);
		assertNull(afterDelete);
	}
}
